@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Space+Grotesk:wght@300;400;500;600&display=swap');

:root {
  --void: #02020c;
  --indigo: #6366f1;
  --violet: #8b5cf6;
  --lavender: #c4b5fd;
  --gold: #e4b84a;
  --white: #f1f5f9;
  --dim: rgba(241, 245, 249, 0.45);
  --dimmer: rgba(241, 245, 249, 0.18);
  --glass-bg: rgba(8, 8, 28, 0.72);
  --glass-border: rgba(139, 92, 246, 0.18);
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-5: 1.5rem;
  --space-6: 2rem;
  --space-7: 3rem;
  --space-8: 4rem;
  --ease-snappy: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-smooth: cubic-bezier(0.4, 0, 0.2, 1);
}

*:focus-visible {
  outline: 2px solid rgba(139, 92, 246, 0.6);
  outline-offset: 3px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  height: 100%;
  overflow: hidden;
  background: var(--void);
  color: var(--white);
  font-family: 'Space Grotesk', system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
  overscroll-behavior: none;

input.content:
.panel {
  display: flex;
  flex-direction: column;
  height: 100%;
  gap: var(--space-4);
  padding: var(--space-5);
  overflow-y: auto;
}

.queryRow {
  display: flex;
  gap: var(--space-3);
  align-items: flex-start;
}

.queryInput {
  flex: 1;
  background: var(--glass-bg);
  border: 1px solid var(--glass-border);
  border-radius: 10px;
  padding: var(--space-3) var(--space-4);
  color: var(--white);
  font-family: inherit;
  font-size: 0.95rem;
  resize: none;
  min-height: 80px;
  transition: border-color 0.2s var(--ease-smooth);
}
.queryInput:focus {
  outline: none;
  border-color: var(--violet);
}

.submitBtn {
  padding: var(--space-3) var(--space-5);
  background: linear-gradient(135deg, var(--indigo), var(--violet));
  border: none;
  border-radius: 10px;
  color: var(--white);
  font-family: inherit;
  font-size: 0.9rem;
  font-weight: 600;
  cursor: pointer;
  white-space: nowrap;
  transition: opacity 0.2s;
}
.submitBtn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

/* Mode badge */
.modeBadge {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: 2px var(--space-3);
  border-radius: 99px;
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}
.grounded  { background: rgba(34,197,94,0.18); color: #4ade80; border: 1px solid rgba(34,197,94,0.3); }
.inferred  { background: rgba(234,179,8,0.18);  color: #facc15; border: 1px solid rgba(234,179,8,0.3);  }
.abstained { background: rgba(100,116,139,0.2); color: #94a3b8; border: 1px solid rgba(100,116,139,0.3); }
.blocked   { background: rgba(239,68,68,0.18);  color: #f87171; border: 1px solid rgba(239,68,68,0.3);  }

/* Result card */
.resultCard {
  background: var(--glass-bg);
  border: 1px solid var(--glass-border);
  border-radius: 14px;
  padding: var(--space-5);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
}

.resultHeader {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  flex-wrap: wrap;
}

.runId {
  font-size: 0.7rem;
  color: var(--dim);
  font-family: monospace;
  margin-left: auto;
}

.confidence {
  font-size: 0.8rem;
  color: var(--lavender);
}

.answerText {
  font-size: 0.95rem;
  line-height: 1.7;
  color: var(--white);
  white-space: pre-wrap;
}

/* Approval banner */
.approvalBanner {
  background: rgba(234,179,8,0.12);
  border: 1px solid rgba(234,179,8,0.35);
  border-radius: 8px;
  padding: var(--space-3) var(--space-4);
  font-size: 0.85rem;
  color: #facc15;
}

/* Citations */
.section {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
}

.sectionTitle {
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--dim);
}

.citation {
  background: rgba(99,102,241,0.08);
  border: 1px solid rgba(99,102,241,0.18);
  border-radius: 8px;
  padding: var(--space-2) var(--space-3);
  font-size: 0.82rem;
}

.citationSource {
  font-weight: 600;
  color: var(--lavender);
  margin-bottom: var(--space-1);
  display: flex;
  justify-content: space-between;
}

.citationRelevance {
  font-size: 0.7rem;
  color: var(--dim);
}

.citationExcerpt {
  color: var(--dim);
  font-style: italic;
}

/* Unresolved */
.unresolved {
  font-size: 0.83rem;
  color: #facc15;
  padding-left: var(--space-3);
  border-left: 2px solid rgba(234,179,8,0.4);
}

/* Stage trace */
.traceGrid {
  display: grid;
  grid-template-columns: auto auto 1fr auto;
  gap: var(--space-1) var(--space-3);
  font-size: 0.75rem;
  font-family: monospace;
}

.traceStage { color: var(--lavender); }
.traceStatus { }
.traceStatusPass    { color: #4ade80; }
.traceStatusFail    { color: #f87171; }
.traceStatusPending { color: #facc15; }
.traceDetails { color: var(--dim); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
.traceMs { color: var(--dim); text-align: right; }

.error {
  background: rgba(239,68,68,0.12);
  border: 1px solid rgba(239,68,68,0.3);
  border-radius: 8px;
  padding: var(--space-3) var(--space-4);
  color: #f87171;
  font-size: 0.9rem;
}

