   239→async function try(
   240→  encoder: TextEncoder,
   241→  system: string,
   242→  user: string,
   243→  history: Msg[] | undefined
   244→): Promise<ReadableStream> {
   245→  let lastErr: unknown;
   246→  for (const key of _KEYS) {
   247→    try {
   248→      const genai = new GoogleGenAI({ apiKey: key });
   249→      const History = (history || []).map(h => ({
   250→        role: h.role === 'omega' ? 'model' : 'user',
   251→        parts: [{ text: h.text }],
   252→      }));
   253→      const chat = genai.chats.create({
   254→        model: '-2.5-flash',
   255→        config: { systemInstruction: system, temperature: 0.85, maxOutputTokens: 4096 },
   256→        history: History,
   257→      });
   258→      const stream = await chat.sendMessageStream({ message: user });
   259→      return new ReadableStream({
   260→        async start(ctrl) {
   261→          for await (const chunk of stream) {
   262→            const text = chunk.text ?? '';
   263→            if (text) ctrl.enqueue(encoder.encode(text));
   264→          }
   265→          ctrl.close();
   266→        }
   267→      });
   268→    } catch (e) {
   269→      lastErr = e;
   270→    }
   271→  }
   272→  throw lastErr ?? new Error('All  keys exhausted');
   273→}
