   277→export async function POST(req: NextRequest) {
   278→  try {
   279→    const { user, history, sessionId } = (await req.json()) as { user: string; history?: Msg[]; sessionId?: string };
   280→
   281→    if (!user?.trim()) {
   282→      return NextResponse.json({ error: 'Missing message' }, { status: 400 });
   283→    }
   284→
   285→    const dbUrl = process.env.DATABASE_URL;
   286→    let finalSessionId = sessionId;
   287→
   288→    if (dbUrl && !finalSessionId) {
   289→      try {
   290→        const db = neon(dbUrl);
   291→        const res = await db`INSERT INTO omega_sessions DEFAULT VALUES RETURNING id`;
   292→        if (res?.length > 0) finalSessionId = res[0].id as string;
   293→      } catch (e) {
   294→        console.error('[OmegA] Session creation failed', e);
   295→      }
   296→    }
   297→
   298→    const encoder = new TextEncoder();
   299→    const decoder = new TextDecoder();
   300→    let provider = 'unknown';
   301→
   302→    const customStream = new ReadableStream({
   303→      async start(controller) {
   304→        try {
   305→          controller.enqueue(encoder.encode('data: {"type":"status","text":"reading memory..."}\n\n'));
   306→
   307→          if (dbUrl && finalSessionId) {
   308→            const db = neon(dbUrl);
   309→            db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'user', ${user})`
   310→              .catch(e => console.error('[OmegA] DB write error', e));
   311→          }
   312→
   313→          let rawContext: string;
   314→          try {
   315→            rawContext = await pullRawContext(user);
   316→          } catch (e) {
   317→            console.warn('[OmegA] DB pull failed:', e);
   318→            rawContext = '(Memory bank unreachable — reasoning independently)';
   319→          }
   320→
   321→          controller.enqueue(encoder.encode('data: {"type":"status","text":"synthesizing..."}\n\n'));
   322→
   323→          const conversationContext = history?.length
   324→            ? `\n━━━ SESSION CONVERSATION HISTORY ━━━\n\n` +
   325→              history.map(m => `[${m.role === 'omega' ? 'OmegA' : 'User'}]: ${m.text}`).join('\n\n') +
   326→              `\n\n━━━ END HISTORY ━━━\n`
   327→            : '';
   328→
   329→          const system = `${SYNTHESIS_DIRECTIVE}\n\n━━━ RAW DATA FROM MEMORY SYSTEMS ━━━\n\n${rawContext}\n\n━━━ END RAW DATA ━━━\n${conversationContext}`;
   330→
   331→          // ── Provider waterfall ──────────────────────────────────────────
   332→          // 1. Vercel AI Gateway (grok-3-fast, $5 free credits)
   333→          // 2. xAI direct       (grok-3-fast, pure credit, no daily cap)
   334→          // 3.  Flash     (key rotation across 3 keys, free tier)
   335→
   336→          let responseStream: ReadableStream;
   337→
   338→          const providers: Array<{ name: string; fn: () => Promise<ReadableStream> }> = [
   339→            { name: 'vercel-gateway', fn: () => tryVercelGateway(encoder, system, user, history) },
   340→            { name: 'xai-direct',    fn: () => tryXaiDirect(encoder, system, user, history) },
   341→            { name: '-flash',  fn: () => try(encoder, system, user, history) },
   342→          ];
   343→
   344→          let lastErr: unknown;
   345→          responseStream = null!;
   346→
   347→          for (const p of providers) {
   348→            try {
   349→              responseStream = await p.fn();
   350→              provider = p.name;
   351→              break;
   352→            } catch (e) {
   353→              console.warn(`[OmegA] ${p.name} failed:`, e);
   354→              lastErr = e;
   355→            }
   356→          }
   357→
   358→          if (!responseStream) throw lastErr ?? new Error('All providers failed');
   359→
   360→          // ── Pipe & persist ───────────────────────────────────────────────
   361→          let fullResponse = '';
   362→          const reader = responseStream.getReader();
   363→          while (true) {
   364→            const { value, done } = await reader.read();
   365→            if (done) break;
   366→            fullResponse += decoder.decode(value, { stream: true });
   367→            controller.enqueue(value);
   368→          }
   369→          fullResponse += decoder.decode();
   370→
   371→          if (dbUrl && finalSessionId && fullResponse) {
   372→            const db = neon(dbUrl);
   373→            db`INSERT INTO omega_chat_messages (session_id, role, content) VALUES (${finalSessionId}, 'omega', ${fullResponse})`
   374→              .catch(e => console.error('[OmegA] DB save error', e));
   375→          }
   376→
   377→          controller.close();
   378→        } catch (err) {
   379→          console.error('[OmegA] Stream error', err);
   380→          controller.error(err);
   381→        }
   382→      }
   383→    });
   384→
   385→    return new NextResponse(customStream, {
   386→      headers: {
   387→        'Content-Type': 'text/plain; charset=utf-8',
   388→        'X-Session-Id': finalSessionId || '',
   389→        'X-Provider': provider,
   390→      }
   391→    });
   392→
   393→  } catch (err) {
   394→    console.error('[OmegA] POST error', err);
   395→    return NextResponse.json({ error: String(err) }, { status: 500 });
   396→  }
   397→}
