      if (avg < 5) {
        if (!silenceTimerRef.current) {
          silenceTimerRef.current = setTimeout(() => {
            silenceTimerRef.current = null;
            if (mediaRecorderRef.current?.state === 'recording') {
              stopMicAnalyzer();
              mediaRecorderRef.current.stop();
            }
          }, 1500);
